function arrayRankTransform(arr) {
    const sortedArr = [...arr].sort((a, b) => a - b);
    const rankMap = {};
    let rank = 1;

    for(const num of sortedArr) {
        if(!(num in rankMap)) {
            rankMap[num] = rank++;
        }
    }

    return arr.map(num => rankMap[num]);
}
```

